digraph G {
    rankdir=LR;
    node [shape=box];
    edge [fontsize=10];

    subgraph cluster_initial {
        label="1. Initial Setup";
        DS1 [label="DS → SEG1"];
        SI1 [label="SI → offset of ARR1"];
        DS1 -> SI1 [style=invis];
    }

    subgraph cluster_min {
        label="2. Find Min in ARR1";
        AL1 [label="AL = candidate"];
        loop1 [label="Loop: Compare AL with [SI]\nUpdate AL if smaller"];
        DL [label="Result (min) stored in DL"];
        AL1 -> loop1 -> DL;
    }

    subgraph cluster_switch1 {
        label="3. Switch to SEG2";
        DS2 [label="DS → SEG2"];
        SI2 [label="SI → offset of ARR2"];
        DS2 -> SI2 [style=invis];
    }

    subgraph cluster_max {
        label="4. Find Max in ARR2";
        AL2 [label="AL = candidate"];
        loop2 [label="Loop: Compare AL with [SI]\nUpdate AL if larger"];
        DH [label="Result (max) stored in DH"];
        AL2 -> loop2 -> DH;
    }

    subgraph cluster_avg {
        label="5. Compute Average";
        add [label="AL = DL (min) + DH (max)"];
        rcr [label="AL = RCR AL, 1\n(floor division by 2)"];
        add -> rcr;
    }

    subgraph cluster_store {
        label="6. Store Result";
        DS3 [label="DS → SEG3"];
        store [label="[AVG] ← AL"];
        DS3 -> store [style=invis];
    }

    subgraph cluster_segments {
        label="Segment Layout";
        SEG1 [label="SEG1: [12H][34H][0AH][78H][56H] (ARR1)"];
        SEG2 [label="SEG2: [9AH][45H][67H][23H][0FH][8BH] (ARR2)"];
        SEG3 [label="SEG3: [avg] (Result)"];
        SEG1 -> SEG2 -> SEG3 [style=invis];
    }

    DS1 -> AL1 [label="start"];
    DL -> DS2 [label="switch"];
    DH -> add [label="compute"];
    rcr -> DS3 [label="store"];
}

